func (sd *SWIMDetector) Rounds() uint64 {
	sd.mu.Lock()
	defer sd.mu.Unlock()
	return sd.roundCount
}

// SuspectCount returns the number of currently suspected members.
func (sd *SWIMDetector) SuspectCount() int {
