			result.Exchanges++
			result.PushedTotal += exchange.PushedTo
			result.PulledTotal += exchange.PulledFrom

			ns.recordEvent(Event{
				Time:    ns.clock,
				Type:    EventGossip,
				Source:  nodeID,
