   116	// Tries all other workers and returns the first successful steal.
   117	func (p *WorkStealingPool) Steal(thiefID string) (interface{}, string, bool) {
   118		p.mu.RLock()
   119		defer p.mu.RUnlock()
   120		for workerID, d := range p.deques {
   121			if workerID == thiefID {
   122				continue
   123			}
   124			item, ok := d.StealTop()
   125			if ok {
   126				p.stolen.Add(1)
   127				return item, workerID, true
   128			}
   129		}
   130		return nil, "", false
   131	}
   132	
   133	// TotalPending returns the total work items across all deques.
   134	func (p *WorkStealingPool) TotalPending() int {
   135		p.mu.RLock()
   136		defer p.mu.RUnlock()
   137		total := 0
   138		for _, d := range p.deques {
   139			total += d.Len()
   140		}
   141		return total
   142	}
   143	
   144	// StolenCount returns the total number of successful steals.
   145	func (p *WorkStealingPool) StolenCount() uint64 {
   146		return p.stolen.Load()
   147	}
   148	
   149	// WorkerCount returns the number of registered workers.
   150	func (p *WorkStealingPool) WorkerCount() int {
   151		p.mu.RLock()
   152		defer p.mu.RUnlock()
   153		return len(p.deques)
   154	}

