   442	func TestWSP_ConcurrentStealCount(t *testing.T) {
   443		const tasks = 1000
   444		const thieves = 8
   445	
   446		p := NewWorkStealingPool()
   447		p.Register("owner")
   448		for i := 0; i < thieves; i++ {
   449			p.Register(string(rune('a' + i)))
   450		}
   451		for i := 0; i < tasks; i++ {
   452			p.Submit("owner", i)
   453		}
   454	
   455		start := make(chan struct{})
   456		results := make(chan int, tasks)
   457		var wg sync.WaitGroup
   458		for i := 0; i < thieves; i++ {
   459			thiefID := string(rune('a' + i))
   460			wg.Add(1)
   461			go func() {
   462				defer wg.Done()
   463				<-start
   464				for {
   465					item, _, ok := p.Steal(thiefID)
   466					if !ok {
   467						return
   468					}
   469					results <- item.(int)
   470				}
   471			}()
   472		}
   473	
   474		close(start)
   475		wg.Wait()
   476		close(results)
   477	
   478		count := 0
   479		for range results {
   480			count++
   481		}
   482		if count != tasks {
   483			t.Fatalf("expected %d stolen tasks, got %d", tasks, count)
   484		}
   485		if p.StolenCount() != tasks {
   486			t.Fatalf("expected stolen count %d, got %d", tasks, p.StolenCount())
   487		}
   488	}
